import request from '@/utils/request';
// 获取用户列表
export function getUserList(params) {
    return request({
        url: '/users/list',
        method: 'get',
        params
    }).then(data => data);
}
// 获取用户详情
export function getUserDetail(id) {
    return request({
        url: `/users/${id}`,
        method: 'get'
    }).then(data => data);
}
// 添加用户
export function addUser(data) {
    return request({
        url: '/users',
        method: 'post',
        data
    }).then(data => data);
}
// 更新用户
export function updateUser(data) {
    return request({
        url: `/users/${data.id}`,
        method: 'put',
        data
    }).then(data => data);
}
// 删除用户
export function deleteUser(id) {
    return request({
        url: `/users/${id}`,
        method: 'delete'
    });
}
// 重置密码
export function resetPassword(id) {
    return request({
        url: `/users/${id}/reset-password`,
        method: 'put'
    });
}
// 启用用户
export function enableUser(id) {
    return request({
        url: `/users/${id}/status`,
        method: 'put',
        params: { enabled: true }
    });
}
// 禁用用户
export function disableUser(id) {
    return request({
        url: `/users/${id}/status`,
        method: 'put',
        params: { enabled: false }
    });
}
// 获取角色列表
export function getRoleList() {
    return request({
        url: '/users/roles',
        method: 'get'
    });
}
